var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"후우. 화려하게 튀겨졌군.","JPN":"ふう。派手に散らしたな。","ENG":"Phew. Fried to a crisp.","TWN":"呼，真是過癮。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"고마워. 대령. 덕분에 임무를 무사히 끝낼 수 있었어.","JPN":"ありがとう。大佐。おかげで無事に任務を終えた。","ENG":"Thanks, Colonel. I was able to finish my mission because of your help.","TWN":"多虧有你，我才能順利完成任務。謝謝你，上校。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"나야말로.","JPN":"こっちらこそ。","ENG":"No, thank you.","TWN":"我才要謝謝你。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"다른 세계의 나도 이렇게 강한 모습을 보니 가슴이 벅차오르는데?","JPN":"違う世界の俺もこんなに強いということを見たんだ、ワクワクするな。","ENG":"My heart is overwhelmed to see myself from another world be so strong!","TWN":"看到另一個世界的我也這麼強，真是令人熱血沸騰呢。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"하하하하하!","JPN":"ははははは！","ENG":"Hah hah hah!","TWN":"哈哈哈哈哈！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"하하하하하!","JPN":"ははははは！","ENG":"Hah hah hah!","TWN":"哈哈哈哈哈！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"윽……근육 바보가 둘이야. 속이 메스꺼워…….","JPN":"うっ……筋肉バカが二人だよ。気持ち悪い……","ENG":"Ngh... There are two musclebrains now... It's making me feel sick...","TWN":"呃……竟然有二個肌肉傻瓜，我覺得噁心想吐……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"후우~ 간만에 진귀한 경험을 했어.","JPN":"ふう～久々に珍しい経験をした。","ENG":"Whew...! Well, that's not something you see every day.","TWN":"呼～真是一次難得的經驗。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"용병 혐오자가 둘이라니. 정말 끔찍하군.","JPN":"大佐が二人とは。ぞっとするな。","ENG":"Two mercenary haters? Disgusting.","TWN":"竟然有二個上校，好恐怖。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"당신 세계에 대해서 궁금한 게 많아.","JPN":"あんたの世界に関して聞きたいことがたくさんある。","ENG":"I have a lot of questions to ask about your world.","TWN":"我很好奇你所處的世界，"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"하지만……왠지 알면 안 될 것 같은 기분이 들어.","JPN":"だが……何だか知ってはいけない気がする。","ENG":"But... I feel like I shouldn't ask.","TWN":"但是……總覺得知道太多似乎又不太好。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"때로는 모르는 게 약인 법도 있으니까 말이야.","JPN":"知らぬが仏というからな。","ENG":"Because sometimes, ignorance is bliss.","TWN":"有時候不要知道太多反而比較好。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"그런 건 중요한 게 아니야. 제이시 워커.","JPN":"そんなことは重要ではないぞ。ジェイシー・ウォーカー大佐。","ENG":"That's not what's important here, Jacey Walker.","TWN":"我的世界不重要，潔西·沃克上校。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"정말로 중요한 건…….","JPN":"本当に大事なのは……","ENG":"What's important is...","TWN":"真正重要的是……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"우리가 약자를 지키고, 본분을 다하는 군인이라는 것.","JPN":"俺たちが弱者を守り、義務を全うする軍人だということ。","ENG":"that we are soldiers who perform our duties and protect the weak.","TWN":"雖然我們身在不同的世界，但我們都是保護弱者，謹守本分的軍人。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"그것만 알고 있으면 돼.","JPN":"それだけを念頭に置いておけばいい。","ENG":"That's all you need to know.","TWN":"你只要記住這一點就好。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"……훗.","JPN":"……ふっ。","ENG":"...Heh.","TWN":"……呵。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"그런가?","JPN":"そうか？","ENG":"You think so?","TWN":"是嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"역시 나와 똑같다니까. 마음에 들어.","JPN":"やっぱり、俺にそっくりだな。気に入った。","ENG":"You and I think alike. I like you.","TWN":"果然跟我很像，我喜歡。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"이런.","JPN":"おっと。","ENG":"Oh, my.","TWN":"糟糕，"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"아무래도 작별할 시간이 온 것 같군.","JPN":"どうやら別れの時が来たようだ。","ENG":"I think it's time we said goodbye.","TWN":"我好像該走了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"당신은 지킬 수 있는 것들을 필사적으로 지키도록 해.","JPN":"あんたは守れるものを必死に守るんだな。","ENG":"Do your absolute best to protect what you can.","TWN":"你一定要拼命守護你所在乎的。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"이미 그럴 수 있는 힘도, 친구도 있는 것 같으니까.","JPN":"既にそれができる力も、友もいるようだから。","ENG":"Because you seem to already have the power and friends to do so.","TWN":"因為無論是能力或是夥伴，你都已經具備。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"오랜만에 보고 싶었던 아이를 보니 헤어지기 좀 아쉽네.","JPN":"久々に会いたかった子を見たから、別れるのが名残惜しいな。","ENG":"It's a little sad to say goodbye after meeting someone I'd wanted to see for a long time.","TWN":"好不容易才見到你，現在要離開真有點捨不得呢。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"잘......지켜줘야 해.","JPN":"ちゃんと……守ってあげるんだ。","ENG":"Keep... her safe.","TWN":"好好…盡你的本分。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"……명심하지.","JPN":"……心に誓おう。","ENG":"...I will.","TWN":"……我會記住的。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};